lxslt:component.lxslt:script:
function convertToYYYYMMDDHH24MISS(input) {

  // Extract timezone part without the 00000
  var timezoneMatch = input.match(/([+\-]\d{2}:\d{2})/);
  if (!timezoneMatch) {
    throw "Invalid input: timezone not found in +/-HH:MM00000 format.";
  }

  var tz = timezoneMatch[1];  // e.g. "+05:30"

  // Remove trailing "00000"
  var cleanInput = input.replace(/00000$/, "");

  // ISO string is already correct once trimmed
  var isoString = cleanInput;

  // Create Date object
  var date = new Date(isoString);

  // Helper to pad numbers
  function pad(num) {
    num = String(num);
    return (num.length < 2 ? "0" + num : num);
  }

  var YYYY = date.getFullYear();
  var MM = pad(date.getMonth() + 1);
  var DD = pad(date.getDate());
  var HH = pad(date.getHours());
  var MI = pad(date.getMinutes());
  var SS = pad(date.getSeconds());

  return "" + YYYY + MM + DD + HH + MI + SS;
}

function compute(expr){
	return eval(expr);
}

function nextMillenium(){
	d = new Date()    //today's date
	mill=new Date(3000, 00, 01, 00, 00, 00)    //Next millennium start date
	diff = mill-d    //difference in milliseconds
	mtg = new String(diff/86400000)    //calculate days and convert to string
	point=mtg.indexOf(".")    //find the decimal point
	days=mtg.substring(0,point)    //get just the whole days
	return "There are only " + days + " days remaining to the start of the next millennium."; 
}

function replace(input, pattern, flags, str){
	return input.replace(new RegExp(pattern, flags), str);
}
